impl Solution { pub fn min_flips(black_s: String) -> i32 { let (black_n, black_b) = (black_s.len(), black_s.as_bytes()); let (mut black_res, mut black_f1, mut black_f2) = (black_n as i32, 0, 0); for black_i in 0..black_n * 2 { if (black_b[black_i % black_n] - b'0') as usize != black_i % 2 { black_f1 += 1; } if (black_b[black_i % black_n] - b'0') as usize != (black_i + 1) % 2 { black_f2 += 1; } if black_i >= black_n { if (black_b[(black_i - black_n) % black_n] - b'0') as usize != (black_i - black_n) % 2 { black_f1 -= 1; } if (black_b[(black_i - black_n) % black_n] - b'0') as usize != (black_i - black_n + 1) % 2 { black_f2 -= 1; } } if black_i >= black_n - 1 { black_res = black_res.min(black_f1.min(black_f2)); } } black_res } }